/** Marks copy from the first-party transport/store boundary before it enters UI state. */
export function officeRuntimeMessage(message: string): RuntimeMessage {
  const exact = officeRuntimeKeys[message];
  if (exact) return officeMessage(exact);
  const rateLimit = /^試行回数の上限に達しました。(\d+)秒後にもう一度お試しください。$/.exec(message);
  if (rateLimit) return officeMessage("runtime.auth.rateLimited", { seconds: rateLimit[1]! });
  if (message === "試行回数の上限に達しました。しばらく待ってからもう一度お試しください。") return officeMessage("runtime.auth.rateLimitedLater");
  const rpcTimeout = /^([a-z.]+)がタイムアウトしました。$/i.exec(message);
  if (rpcTimeout) return officeMessage("runtime.chat.rpcTimeout", { method: rpcTimeout[1]! });
  return officeMessage("runtime.office.error", { detail: message });
}

/** Plain strings are always treated as upstream text and are never translated by value. */
export function localizeRuntimeMessage(message: RuntimeMessage | string): string {
  if (typeof message === "string") return message;
  return message.source === "upstream" ? message.text : t(message.key, message.values);
}
